def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 7) / (a * b * 0.8 + 1)
                    term2 = np.exp(-ratio / (b + 1))
                    priority += term1 * np.cos(ratio * b / (a + 2)) + term2 * np.sin(ratio * a)
            priority += (np.sinh(ratio - 10) * np.cos(2 * ratio)) ** 2.2
        elif 6 < ratio <= 10:
            for m in range(1, int(np.ceil(ratio)) + 5):
                for n in range(1, m + 4):
                    temp = ((ratio - m) ** 4) * np.sin(ratio * m) / (n + 0.7)
                    priority += np.tanh(temp) * 1.5
            priority += np.log(ratio) * 15 - np.tanh(ratio - 6) * 3
        elif 4 <= ratio <= 6:
            acc = 0
            for p in range(1, 15):
                acc += ((ratio - 4) ** p) / (p * 2.2) * np.cos(p * ratio * 1.5)
            priority = (acc * np.cos(10 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (6 - ratio)) * 2
        elif 2 <= ratio < 4:
            s = 0
            for q in range(1, 15):
                s += ((4 - ratio) ** q) / (q ** 2 + 1)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for r in range(1, 7):
                priority += np.sin(r * ratio * i * 1.1) * ((ratio - 1.9) ** r) / r
        elif 0.5 <= ratio < 2:
            v = 0
            for s_idx in range(1, 18):
                v += ((2 - ratio) ** s_idx) / (s_idx * 5)
            priority = v
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 3) + 5)
            for t in range(1, 9):
                priority += ((2 - ratio) ** t) * np.sin(t * item * 1.6) * 0.9
        elif 0.15 <= ratio < 0.5:
            val = 0
            for u in range(1, 20):
                val += ((0.5 - ratio) ** u) / (u * 4) * np.cos(u * ratio * 3)
            priority = val + 2 / (bin_cap + 5)
            if int(item * 2.1) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for w in range(1, 10):
                priority += ((0.5 - ratio) ** w) / (w * 8) * np.cos(item * w * 1.3)
        else:
            z = 0
            for x in range(1, 15):
                z += ((0.15 - ratio) ** x) / (x * 6) * np.sin(x * item * 1.0)
            priority = z + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for y in range(1, 10):
                priority += ((0.15 - ratio) ** y) / (y * 9) * np.cos(item * y * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.5 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6.5
        for idx2 in range(1, 6):
            if (i + idx2) % 4 == 0:
                priority += np.sin(ratio * (i + idx2) * 1.2) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx2) * 1.2) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        for w in range(1, 4):
            if (i * w + int(ratio * 10)) % 5 == 0:
                priority += np.tanh(ratio * i * w) * 0.4
            else:
                priority -= np.sinh(ratio / (i + w + 0.5)) * 0.4
        priorities[i] = priority
    return priorities
